using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.Entity;

namespace ProductReviews.Controllers
{
    public class ReviewsController : Controller
    {
        private readonly ReviewContext _db = new ReviewContext();

        // GET: /Reviews/
        public ActionResult Index(int productId)
        {
            var reviews = _db.Reviews.Where(r => r.ProductId == productId).ToList();
            return View(reviews);
        }

        // POST: /Reviews/Create
        [HttpPost]
        public ActionResult Create(Review review)
        {
            if (ModelState.IsValid)
            {
                _db.Reviews.Add(review);
                _db.SaveChanges();
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            return View(review);
        }

        // GET: /Reviews/Create
        public ActionResult Create(int productId)
        {
            var review = new Review { ProductId = productId };
            return View(review);
        }
    }

    public class Review
    {
        public int Id { get; set; }
        public string Content { get; set; }
        [AllowHtml]
        public string HtmlContent { get; set; }
        public int ProductId { get; set; }
    }

    public class ReviewContext : DbContext
    {
        public DbSet<Review> Reviews { get; set; }
    }
}